{
  "name": "VoxVeritas - Voice Authenticity Detector",
  "description": "An MVP for detecting AI-generated vs. Human voices in Tamil, English, Hindi, Malayalam, and Telugu using Gemini's multimodal forensic analysis.",
  "requestFramePermissions": ["microphone"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Language {
  TAMIL = 'Tamil',
  ENGLISH = 'English',
  HINDI = 'Hindi',
  MALAYALAM = 'Malayalam',
  TELUGU = 'Telugu'
}

export enum DetectionStatus {
  AI_GENERATED = 'AI-generated',
  HUMAN_GENERATED = 'Human-generated'
}

export interface DetectionResult {
  classification: DetectionStatus;
  confidence: number;
  explanation: string;
  technicalArtifacts: string[];
}

export interface AppState {
  audioFile: File | null;
  audioBase64: string | null;
  selectedLanguage: Language;
  isAnalyzing: boolean;
  result: DetectionResult | null;
  error: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Language, DetectionResult, DetectionStatus } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeVoiceAuthenticity = async (
  base64Audio: string,
  language: Language
): Promise<DetectionResult> => {
  const model = "gemini-3-pro-preview";

  const systemInstruction = `
    You are an expert Audio Forensic Engineer specialized in detecting synthetic speech (AI-generated voices).
    Analyze the provided audio sample in the context of the ${language} language.

    Evaluate the following criteria:
    1. Spectral consistency: Look for digital artifacts or robotic frequency shifts.
    2. Breathing patterns: Humans have natural pauses and inhale sounds; AI often lacks these or generates them unnaturally.
    3. Linguistic nuances: Check if the pronunciation of ${language} sounds natural or has the digital flatness typical of TTS (Text-to-Speech) engines.
    4. Prosody and Rhythm: AI often has perfectly consistent or slightly jerky rhythm, while humans vary naturally.

    Provide your analysis as a structured JSON response.
  `;

  const response = await ai.models.generateContent({
    model: model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "audio/mp3",
            data: base64Audio,
          },
        },
        {
          text: `Analyze this audio sample to determine if it is human or AI-generated in the ${language} language. Return only JSON.`,
        },
      ],
    },
    config: {
      systemInstruction: systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          classification: {
            type: Type.STRING,
            description: "Must be exactly 'AI-generated' or 'Human-generated'",
          },
          confidence: {
            type: Type.NUMBER,
            description: "A probability score between 0 and 1",
          },
          explanation: {
            type: Type.STRING,
            description: "A detailed explanation of why this conclusion was reached",
          },
          technicalArtifacts: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of specific forensic markers observed",
          },
        },
        required: ["classification", "confidence", "explanation", "technicalArtifacts"],
      },
    },
  });

  const resultText = response.text;
  if (!resultText) throw new Error("No response from AI model.");

  try {
    const json = JSON.parse(resultText);
    return {
      classification: json.classification as DetectionStatus,
      confidence: json.confidence,
      explanation: json.explanation,
      technicalArtifacts: json.technicalArtifacts,
    };
  } catch (err) {
    console.error("Failed to parse Gemini response:", resultText);
    throw new Error("Invalid response format from analysis engine.");
  }
};

import React, { useState, useCallback, useRef } from 'react';
import { Language, AppState, DetectionStatus, DetectionResult } from './types';
import { analyzeVoiceAuthenticity } from './geminiService';

const LANGUAGES = [
  Language.TAMIL,
  Language.ENGLISH,
  Language.HINDI,
  Language.MALAYALAM,
  Language.TELUGU,
];

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    audioFile: null,
    audioBase64: null,
    selectedLanguage: Language.ENGLISH,
    isAnalyzing: false,
    result: null,
    error: null,
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.type !== 'audio/mpeg' && file.type !== 'audio/mp3') {
        setState(prev => ({ ...prev, error: "Please upload an MP3 file." }));
        return;
      }

      const reader = new FileReader();
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        setState(prev => ({
          ...prev,
          audioFile: file,
          audioBase64: base64,
          error: null,
          result: null
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!state.audioBase64) return;

    setState(prev => ({ ...prev, isAnalyzing: true, error: null }));
    try {
      const result = await analyzeVoiceAuthenticity(state.audioBase64, state.selectedLanguage);
      setState(prev => ({ ...prev, result, isAnalyzing: false }));
    } catch (err: any) {
      setState(prev => ({ ...prev, error: err.message || "Analysis failed.", isAnalyzing: false }));
    }
  };

  const reset = () => {
    setState({
      audioFile: null,
      audioBase64: null,
      selectedLanguage: Language.ENGLISH,
      isAnalyzing: false,
      result: null,
      error: null,
    });
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-8">
      {/* Header */}
      <header className="w-full max-w-4xl flex items-center justify-between mb-12">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-500/20">
            <i className="fas fa-shield-halved text-2xl text-white"></i>
          </div>
          <h1 className="text-2xl font-bold tracking-tight">Vox<span className="text-blue-500">Veritas</span></h1>
        </div>
        <div className="text-sm text-slate-400 font-medium bg-slate-800/50 px-3 py-1 rounded-full border border-slate-700">
          Audio Forensic MVP
        </div>
      </header>

      <main className="w-full max-w-4xl grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Column: Upload & Config */}
        <div className="lg:col-span-5 flex flex-col gap-6">
          <section className="bg-slate-800/40 p-6 rounded-2xl border border-slate-700/50 backdrop-blur-sm">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <i className="fas fa-file-audio text-blue-400"></i>
              Step 1: Upload Sample
            </h2>

            <div 
              className={`relative border-2 border-dashed rounded-xl p-8 transition-all flex flex-col items-center justify-center gap-4 cursor-pointer
                ${state.audioFile ? 'border-green-500/50 bg-green-500/5' : 'border-slate-600 hover:border-blue-500/50 hover:bg-blue-500/5'}`}
              onClick={() => fileInputRef.current?.click()}
            >
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept=".mp3,audio/mpeg"
              />

              {!state.audioFile ? (
                <>
                  <div className="w-12 h-12 bg-slate-700 rounded-full flex items-center justify-center">
                    <i className="fas fa-cloud-arrow-up text-xl text-slate-400"></i>
                  </div>
                  <div className="text-center">
                    <p className="text-sm font-medium">Click to upload or drag & drop</p>
                    <p className="text-xs text-slate-500 mt-1">MP3 format supported</p>
                  </div>
                </>
              ) : (
                <>
                  <div className="w-12 h-12 bg-green-500 rounded-full flex items-center justify-center">
                    <i className="fas fa-check text-xl text-white"></i>
                  </div>
                  <div className="text-center">
                    <p className="text-sm font-medium truncate max-w-[200px]">{state.audioFile.name}</p>
                    <p className="text-xs text-slate-400 mt-1">{(state.audioFile.size / 1024).toFixed(1)} KB</p>
                  </div>
                  <button 
                    onClick={(e) => { e.stopPropagation(); reset(); }}
                    className="absolute top-2 right-2 p-2 hover:bg-red-500/10 rounded-full text-slate-500 hover:text-red-400"
                  >
                    <i className="fas fa-times"></i>
                  </button>
                </>
              )}
            </div>
          </section>

          <section className="bg-slate-800/40 p-6 rounded-2xl border border-slate-700/50 backdrop-blur-sm">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <i className="fas fa-language text-blue-400"></i>
              Step 2: Select Language
            </h2>
            <div className="grid grid-cols-2 gap-3">
              {LANGUAGES.map((lang) => (
                <button
                  key={lang}
                  onClick={() => setState(prev => ({ ...prev, selectedLanguage: lang }))}
                  className={`py-2 px-3 rounded-lg text-sm font-medium transition-all border
                    ${state.selectedLanguage === lang 
                      ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-500/20' 
                      : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                >
                  {lang}
                </button>
              ))}
            </div>
          </section>

          <button
            onClick={handleAnalyze}
            disabled={!state.audioBase64 || state.isAnalyzing}
            className={`w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-3 transition-all
              ${!state.audioBase64 || state.isAnalyzing 
                ? 'bg-slate-700 text-slate-500 cursor-not-allowed' 
                : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white shadow-xl shadow-blue-600/20'}`}
          >
            {state.isAnalyzing ? (
              <>
                <i className="fas fa-circle-notch fa-spin"></i>
                Analyzing Forensics...
              </>
            ) : (
              <>
                <i className="fas fa-microscope"></i>
                Verify Audio
              </>
            )}
          </button>

          {state.error && (
            <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-sm flex items-start gap-3">
              <i className="fas fa-triangle-exclamation mt-0.5"></i>
              <span>{state.error}</span>
            </div>
          )}
        </div>

        {/* Right Column: Results */}
        <div className="lg:col-span-7">
          <div className="h-full bg-slate-900/50 rounded-2xl border border-slate-700/50 min-h-[400px] flex flex-col">
            {!state.result && !state.isAnalyzing ? (
              <div className="flex-1 flex flex-col items-center justify-center p-12 text-center">
                <div className="w-20 h-20 bg-slate-800 rounded-2xl flex items-center justify-center mb-6 border border-slate-700">
                  <i className="fas fa-wave-square text-3xl text-slate-600"></i>
                </div>
                <h3 className="text-xl font-semibold mb-2">Awaiting Analysis</h3>
                <p className="text-slate-500 max-w-sm">
                  Upload an audio sample and select the language to perform real-time forensic detection.
                </p>

                <div className="grid grid-cols-2 gap-4 mt-12 w-full text-left">
                  <div className="p-3 bg-slate-800/30 rounded-lg border border-slate-700/30">
                    <p className="text-xs text-blue-400 uppercase font-bold mb-1">Target</p>
                    <p className="text-xs text-slate-400 leading-relaxed">Deepfake detection & TTS synthesis artifacts.</p>
                  </div>
                  <div className="p-3 bg-slate-800/30 rounded-lg border border-slate-700/30">
                    <p className="text-xs text-blue-400 uppercase font-bold mb-1">Languages</p>
                    <p className="text-xs text-slate-400 leading-relaxed">Multilingual support for Indic and English.</p>
                  </div>
                </div>
              </div>
            ) : state.isAnalyzing ? (
              <div className="flex-1 flex flex-col items-center justify-center p-12">
                <div className="relative w-32 h-32 mb-8">
                  <div className="absolute inset-0 border-4 border-blue-500/20 rounded-full"></div>
                  <div className="absolute inset-0 border-4 border-t-blue-500 rounded-full animate-spin"></div>
                  <div className="absolute inset-4 bg-blue-500/10 rounded-full flex items-center justify-center">
                    <i className="fas fa-brain text-3xl text-blue-400 animate-pulse"></i>
                  </div>
                </div>
                <h3 className="text-xl font-semibold mb-2">Analyzing Voice Profile</h3>
                <div className="flex flex-col gap-2 w-full max-w-xs">
                  <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full bg-blue-500 animate-[loading_2s_infinite]"></div>
                  </div>
                  <div className="flex justify-between text-[10px] text-slate-500 font-mono">
                    <span>SPECTRAL SCAN</span>
                    <span>PROSODY CHECK</span>
                    <span>ARTIFACT HUNT</span>
                  </div>
                </div>
                <style>{`
                  @keyframes loading {
                    0% { width: 0%; margin-left: 0%; }
                    50% { width: 40%; margin-left: 60%; }
                    100% { width: 0%; margin-left: 100%; }
                  }
                `}</style>
              </div>
            ) : (
              <div className="flex-1 p-8 overflow-y-auto">
                {/* Result Hero */}
                <div className="flex flex-col md:flex-row items-center gap-8 mb-10">
                  <div className="relative">
                    <svg className="w-32 h-32 transform -rotate-90">
                      <circle cx="64" cy="64" r="58" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-slate-800" />
                      <circle 
                        cx="64" cy="64" r="58" stroke="currentColor" strokeWidth="8" fill="transparent" 
                        strokeDasharray={364}
                        strokeDashoffset={364 - (364 * (state.result?.confidence || 0))}
                        strokeLinecap="round"
                        className={state.result?.classification === DetectionStatus.AI_GENERATED ? 'text-red-500' : 'text-green-500'}
                      />
                    </svg>
                    <div className="absolute inset-0 flex flex-col items-center justify-center">
                      <span className="text-2xl font-bold">{Math.round((state.result?.confidence || 0) * 100)}%</span>
                      <span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Confidence</span>
                    </div>
                  </div>

                  <div className="text-center md:text-left">
                    <p className="text-slate-500 text-sm font-medium uppercase tracking-widest mb-1">Final Classification</p>
                    <h3 className={`text-3xl font-bold mb-2 ${state.result?.classification === DetectionStatus.AI_GENERATED ? 'text-red-400' : 'text-green-400'}`}>
                      {state.result?.classification}
                    </h3>
                    <div className="flex items-center gap-2 px-3 py-1 bg-slate-800 rounded-full border border-slate-700 w-fit mx-auto md:mx-0">
                      <i className="fas fa-fingerprint text-[10px] text-blue-400"></i>
                      <span className="text-xs font-mono text-slate-400">SAMPLE_ID: {Math.random().toString(36).substr(2, 9).toUpperCase()}</span>
                    </div>
                  </div>
                </div>

                {/* Explanation Section */}
                <div className="space-y-6">
                  <section>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-3">Forensic Explanation</h4>
                    <p className="text-slate-300 leading-relaxed bg-slate-800/30 p-4 rounded-xl border border-slate-700/50">
                      {state.result?.explanation}
                    </p>
                  </section>

                  <section>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-3">Detected Artifacts</h4>
                    <div className="flex flex-wrap gap-2">
                      {state.result?.technicalArtifacts.map((artifact, i) => (
                        <div key={i} className="px-3 py-1.5 bg-slate-800 rounded-lg border border-slate-700 text-xs text-slate-300 flex items-center gap-2">
                          <i className={`fas fa-circle text-[6px] ${state.result?.classification === DetectionStatus.AI_GENERATED ? 'text-red-500' : 'text-green-500'}`}></i>
                          {artifact}
                        </div>
                      ))}
                    </div>
                  </section>
                </div>
              </div>
            )}

            {/* Footer Status Bar */}
            <div className="p-4 bg-slate-800/50 border-t border-slate-700 flex justify-between items-center rounded-b-2xl">
              <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                <span className="text-[10px] font-bold text-slate-500 tracking-tighter uppercase">Forensic Engine Ready</span>
              </div>
              <div className="flex items-center gap-4 text-slate-500">
                <i className="fab fa-google text-sm"></i>
                <i className="fas fa-bolt text-sm"></i>
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="mt-16 text-slate-600 text-xs text-center max-w-2xl">
        <p className="mb-2">Powered by Gemini 3.0 Pro Multimodal Analysis. This is an MVP designed for investigative assistance.</p>
        <p>&copy; 2024 VoxVeritas Forensics. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default App;

export enum Language {
  TAMIL = 'Tamil',
  ENGLISH = 'English',
  HINDI = 'Hindi',
  MALAYALAM = 'Malayalam',
  TELUGU = 'Telugu'
}

export enum DetectionStatus {
  AI_GENERATED = 'AI_GENERATED',
  HUMAN = 'HUMAN'
}

export interface DetectionResult {
  status: 'success' | 'error';
  language: Language;
  classification: DetectionStatus;
  confidenceScore: number;
  explanation: string;
  technicalArtifacts: string[]; // Kept for forensic detail in UI
}

export interface AppState {
  audioFile: File | null;
  audioBase64: string | null;
  selectedLanguage: Language;
  isAnalyzing: boolean;
  result: DetectionResult | null;
  error: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Language, DetectionResult, DetectionStatus } from "./types";

export const analyzeVoiceAuthenticity = async (
  base64Audio: string,
  language: Language
): Promise<DetectionResult> => {
  // Creating a fresh instance to ensure up-to-date API key handling
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = "gemini-3-pro-preview";

  const systemInstruction = `
    You are a World-Class Audio Forensic Scientist (Senior Level, Year 2026) specialized in distinguishing between biological human speech and synthetic (AI-generated) audio.

    FORENSIC INVESTIGATION PROTOCOL:
    1. TEMPORAL COHERENCE: Humans have micro-fluctuations in timing (biological jitter). AI often exhibits "perfect" mathematical regularity or unnatural "jerkiness" in complex transitions.
    2. SPECTRAL PURITY: Analyze the 16kHz+ frequency range for quantization artifacts or "fake" noise injection used by advanced 2026-era generators to hide digital signatures.
    3. BIOLOGICAL LATENCY: In languages like ${language}, check for the physical effort of pronouncing retroflex consonants (e.g., in Tamil/Malayalam) or aspirated vowels (Hindi/Telugu). AI often ignores the physical constraints of a human vocal tract.
    4. PROSODIC SMOOTHING: Look for unnatural pitch consistency that bypasses emotional micro-variations.

    You must strictly return a JSON response following the specified schema.
  `;

  const response = await ai.models.generateContent({
    model: model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "audio/mp3",
            data: base64Audio,
          },
        },
        {
          text: `Perform a deep forensic analysis on this MP3 sample. Language: ${language}. Determine if AI_GENERATED or HUMAN.`,
        },
      ],
    },
    config: {
      systemInstruction: systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          status: { type: Type.STRING, description: "Must be 'success'" },
          language: { type: Type.STRING, description: "The language of the audio" },
          classification: { 
            type: Type.STRING, 
            description: "Must be exactly 'AI_GENERATED' or 'HUMAN'" 
          },
          confidenceScore: { 
            type: Type.NUMBER, 
            description: "A probability score between 0.0 and 1.0" 
          },
          explanation: { 
            type: Type.STRING, 
            description: "A professional forensic summary of the findings" 
          },
          technicalArtifacts: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Specific digital or biological markers identified"
          }
        },
        required: ["status", "language", "classification", "confidenceScore", "explanation", "technicalArtifacts"],
      },
    },
  });

  const resultText = response.text;
  if (!resultText) throw new Error("Analysis failed: No output from forensic engine.");

  try {
    const json = JSON.parse(resultText);
    return {
      status: json.status,
      language: json.language as Language,
      classification: json.classification as DetectionStatus,
      confidenceScore: json.confidenceScore,
      explanation: json.explanation,
      technicalArtifacts: json.technicalArtifacts,
    };
  } catch (err) {
    console.error("Forensic Parser Error:", resultText);
    throw new Error("Malformed forensic data received from engine.");
  }
};

import React, { useState, useCallback, useRef } from 'react';
import { Language, AppState, DetectionStatus, DetectionResult } from './types';
import { analyzeVoiceAuthenticity } from './geminiService';

const LANGUAGES = [
  Language.TAMIL,
  Language.ENGLISH,
  Language.HINDI,
  Language.MALAYALAM,
  Language.TELUGU,
];

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    audioFile: null,
    audioBase64: null,
    selectedLanguage: Language.ENGLISH,
    isAnalyzing: false,
    result: null,
    error: null,
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!['audio/mpeg', 'audio/mp3'].includes(file.type)) {
        setState(prev => ({ ...prev, error: "Validation Error: Only MP3 files are accepted for forensic analysis." }));
        return;
      }

      const reader = new FileReader();
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        setState(prev => ({
          ...prev,
          audioFile: file,
          audioBase64: base64,
          error: null,
          result: null
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!state.audioBase64) return;

    setState(prev => ({ ...prev, isAnalyzing: true, error: null }));
    try {
      const result = await analyzeVoiceAuthenticity(state.audioBase64, state.selectedLanguage);
      setState(prev => ({ ...prev, result, isAnalyzing: false }));
    } catch (err: any) {
      setState(prev => ({ ...prev, error: err.message || "Forensic engine failure.", isAnalyzing: false }));
    }
  };

  const reset = () => {
    setState({
      audioFile: null,
      audioBase64: null,
      selectedLanguage: Language.ENGLISH,
      isAnalyzing: false,
      result: null,
      error: null,
    });
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-8 bg-slate-950">
      {/* Header */}
      <header className="w-full max-w-5xl flex items-center justify-between mb-12">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2.5 rounded-xl shadow-xl shadow-indigo-500/20">
            <i className="fas fa-fingerprint text-2xl text-white"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter uppercase italic">Vox<span className="text-indigo-500">Veritas</span></h1>
            <p className="text-[10px] text-slate-500 font-bold tracking-widest uppercase">Forensic Voice Authenticity Lab</p>
          </div>
        </div>
        <div className="hidden md:flex flex-col items-end">
          <div className="text-[10px] text-indigo-400 font-bold bg-indigo-500/10 px-3 py-1 rounded-full border border-indigo-500/20">
            STRATEGIC MVP v2.0
          </div>
          <p className="text-[9px] text-slate-600 mt-1 uppercase font-mono">2026_CORE_ALIGNED</p>
        </div>
