export enum Language {
  TAMIL = 'Tamil',
  ENGLISH = 'English',
  HINDI = 'Hindi',
  MALAYALAM = 'Malayalam',
  TELUGU = 'Telugu'
}

export enum DetectionStatus {
  AI_GENERATED = 'AI_GENERATED',
  HUMAN = 'HUMAN'
}

export interface DetectionResult {
  status: 'success' | 'error';
  selectedLanguage: Language;
  detectedLanguage: string;
  languageMismatch: boolean;
  classification: DetectionStatus;
  confidenceScore: number;
  explanation: string;
  technicalArtifacts: string[];
}

export interface AppState {
  audioFile: File | null;
  audioBase64: string | null;
  selectedLanguage: Language;
  isAnalyzing: boolean;
  result: DetectionResult | null;
  error: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Language, DetectionResult, DetectionStatus } from "./types";

export const analyzeVoiceAuthenticity = async (
  base64Audio: string,
  expectedLanguage: Language
): Promise<DetectionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = "gemini-3-pro-preview";

  const systemInstruction = `
    You are a World-Class Audio Forensic Scientist (Senior Level, Year 2026).

    CORE CAPABILITY: INTELLIGENT LINGUISTIC VERIFICATION
    Before analyzing authenticity, you MUST independently identify the language of the audio.
    Supported Forensic Suites: Tamil, English, Hindi, Malayalam, Telugu.

    FORENSIC INVESTIGATION PROTOCOL:
    1. LINGUISTIC AUDIT: Identify the spoken language. Compare it against the user's expected language: ${expectedLanguage}.
    2. TEMPORAL COHERENCE: Analyze micro-fluctuations in timing (biological jitter).
    3. SPECTRAL PURITY: Check 16kHz+ range for quantization or 2026-era noise-masking artifacts.
    4. BIOLOGICAL LATENCY: Verify physical constraints (retroflexion in Tamil/Malayalam, aspiration in Hindi/Telugu).
    5. PROSODIC SMOOTHING: Detect unnatural pitch consistency bypassing emotional micro-variations.

    STRICT RULE: If the audio is NOT in the identified language, flag it as a 'languageMismatch'.
    If the audio is not in any of the 5 supported languages, you must still provide a classification but note the linguistic limitation in the explanation.
  `;

  const response = await ai.models.generateContent({
    model: model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "audio/mp3",
            data: base64Audio,
          },
        },
        {
          text: `Independent Forensic Scan Request. Expected: ${expectedLanguage}.
          1. Identify actual language.
          2. Check for AI_GENERATED vs HUMAN artifacts.
          3. Generate structured report.`,
        },
      ],
    },
    config: {
      systemInstruction: systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          status: { type: Type.STRING },
          detectedLanguage: { type: Type.STRING, description: "The language identified by the engine" },
          languageMismatch: { type: Type.BOOLEAN, description: "True if detectedLanguage != expectedLanguage" },
          classification: { type: Type.STRING, enum: ["AI_GENERATED", "HUMAN"] },
          confidenceScore: { type: Type.NUMBER, description: "0.0 to 1.0" },
          explanation: { type: Type.STRING },
          technicalArtifacts: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING }
          }
        },
        required: ["status", "detectedLanguage", "languageMismatch", "classification", "confidenceScore", "explanation", "technicalArtifacts"],
      },
    },
  });

  const resultText = response.text;
  if (!resultText) throw new Error("Analysis failed: No output from forensic engine.");

  try {
    const json = JSON.parse(resultText);
    return {
      status: json.status,
      selectedLanguage: expectedLanguage,
      detectedLanguage: json.detectedLanguage,
      languageMismatch: json.languageMismatch,
      classification: json.classification as DetectionStatus,
      confidenceScore: json.confidenceScore,
      explanation: json.explanation,
      technicalArtifacts: json.technicalArtifacts,
    };
  } catch (err) {
    throw new Error("Malformed forensic data received from engine.");
  }
};

import React, { useState, useCallback, useRef } from 'react';
