export enum Language {
  TAMIL = 'Tamil',
  ENGLISH = 'English',
  HINDI = 'Hindi',
  MALAYALAM = 'Malayalam',
  TELUGU = 'Telugu'
}

export enum Classification {
  AI_GENERATED = 'AI_GENERATED',
  HUMAN = 'HUMAN'
}

// The exact JSON response body required by the specification
export interface ApiResponse {
  status: 'success' | 'error';
  language?: string;
  classification?: Classification;
  confidenceScore?: number;
  explanation?: string;
  message?: string; // For error responses
}

// The exact JSON request body required by the specification
export interface ApiRequest {
  language: Language;
