}

import { GoogleGenAI, Type } from "@google/genai";
import { Language, ApiResponse, Classification } from "./types";

export const processVoiceAnalysis = async (
  base64Audio: string,
  userLanguage: Language
): Promise<ApiResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = "gemini-3-pro-preview";

  const systemInstruction = `
    You are the core logic engine for the VoxVeritas Voice Detection REST API (Year 2026).

    TASK: Analyze the provided MP3 audio and classify it as AI_GENERATED or HUMAN.
    SUPPORTED LANGUAGES: Tamil, English, Hindi, Malayalam, Telugu.

    FORENSIC REQUIREMENTS:
    1. INDEPENDENT LANGUAGE VERIFICATION: Identify the language. If it differs from ${userLanguage}, note this in the explanation but proceed with forensic markers relevant to the DETECTED language.
    2. BIOLOGICAL VS SYNTHETIC AUDIT:
       - Check for "Phonatory Jitter" (Biological) vs "Mathematical Smoothing" (AI).
       - Check for "Inhalation Latency" (Biological) vs "Canned Breathing" (AI).
       - Check for "Spectral Quantization" in the 16kHz+ range.

    RESPONSE RULES:
    - You MUST return a valid JSON object.
    - classification MUST be exactly "AI_GENERATED" or "HUMAN".
    - confidenceScore MUST be between 0.0 and 1.0.
    - explanation MUST be a professional, concise forensic reasoning.
    - language field should reflect the identified language.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "audio/mp3",
              data: base64Audio,
            },
          },
          {
            text: `REST API Request. Expected Language Context: ${userLanguage}. Perform classification and return JSON.`,
          },
        ],
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            language: { type: Type.STRING },
            classification: { type: Type.STRING, enum: ["AI_GENERATED", "HUMAN"] },
            confidenceScore: { type: Type.NUMBER },
            explanation: { type: Type.STRING }
          },
          required: ["status", "language", "classification", "confidenceScore", "explanation"],
        },
      },
    });

    const resultText = response.text;
    if (!resultText) throw new Error("Internal Forensic Engine Timeout.");

    const json = JSON.parse(resultText);
    return {
      status: 'success',
      language: json.language,
      classification: json.classification as Classification,
      confidenceScore: json.confidenceScore,
      explanation: json.explanation,
    };
  } catch (err: any) {
    console.error("Internal API Error:", err);
    return {
      status: 'error',
      message: err.message || "Internal Server Error during voice analysis."
    };
  }
};

