import { GoogleGenAI, Type } from "@google/genai";
import { Language, DetectionResult, Classification } from "./types";

export const analyzeVoiceAuthenticity = async (
  base64Audio: string,
  expectedLanguage: Language
): Promise<DetectionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = "gemini-3-pro-preview";

  const systemInstruction = `
    You are a World-Class Audio Forensic Scientist (Year 2026).

    CORE CAPABILITY: AI VOICE DETECTION
    Analyze the provided MP3 audio and classify it as AI_GENERATED or HUMAN.

    FORENSIC INVESTIGATION PROTOCOL:
    1. LINGUISTIC AUDIT: Identify the spoken language (Tamil, English, Hindi, Malayalam, or Telugu).
    2. TEMPORAL COHERENCE: Analyze micro-fluctuations in timing (biological jitter).
    3. SPECTRAL PURITY: Check 16kHz+ range for quantization or artifacts.
    4. TECHNICAL MARKERS: Identify 4 specific forensic markers observed in the clip.

    STRICT JSON RESPONSE FORMAT:
    {
      "status": "success",
      "language": "Detected Language Name",
      "classification": "AI_GENERATED" or "HUMAN",
      "confidenceScore": 0.0 to 1.0,
      "explanation": "Short professional reason",
      "technicalArtifacts": ["Marker 1", "Marker 2", "Marker 3", "Marker 4"]
    }
  `;

  const response = await ai.models.generateContent({
    model: model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "audio/mp3",
            data: base64Audio,
          },
        },
        {
          text: `Forensic Scan Request. Expected: ${expectedLanguage}. Provide analysis in strictly structured JSON.`,
        },
      ],
    },
    config: {
      systemInstruction: systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          status: { type: Type.STRING },
          language: { type: Type.STRING },
          classification: { type: Type.STRING, enum: ["AI_GENERATED", "HUMAN"] },
          confidenceScore: { type: Type.NUMBER },
          explanation: { type: Type.STRING },
          technicalArtifacts: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING }
          }
        },
        required: ["status", "language", "classification", "confidenceScore", "explanation", "technicalArtifacts"],
      },
    },
  });

  const resultText = response.text;
  if (!resultText) throw new Error("Analysis failed: No output from engine.");

  try {
    const json = JSON.parse(resultText);
    return {
      status: json.status,
      language: json.language,
      classification: json.classification as Classification,
      confidenceScore: json.confidenceScore,
      explanation: json.explanation,
      technicalArtifacts: json.technicalArtifacts,
    };
  } catch (err) {
    throw new Error("Malformed forensic data received.");
  }
};

import React, { useState, useRef } from 'react';
import { Language, AppState, Classification, DetectionResult } from './types';
import { analyzeVoiceAuthenticity } from './geminiService';

const LANGUAGES = [
  Language.TAMIL,
  Language.ENGLISH,
  Language.HINDI,
  Language.MALAYALAM,
  Language.TELUGU,
];

