  const [state, setState] = useState<AppState>({
    audioFile: null,
    audioBase64: null,
    selectedLanguage: Language.ENGLISH,
    isAnalyzing: false,
    result: null,
    error: null,
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        setState(prev => ({ 
          ...prev, 
          audioFile: file, 
          audioBase64: base64, 
          error: null, 
          result: null 
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!state.audioBase64) return;
    setState(prev => ({ ...prev, isAnalyzing: true, error: null }));
    try {
      const result = await analyzeVoiceAuthenticity(state.audioBase64, state.selectedLanguage);
      setState(prev => ({ ...prev, result, isAnalyzing: false }));
    } catch (err: any) {
      setState(prev => ({ 
        ...prev, 
        error: err.message || "Forensic engine failure.", 
        isAnalyzing: false 
      }));
    }
  };

  // Prepares the JSON for the code block as per user requirement
  const getRequiredJson = (result: DetectionResult) => {
    const { status, language, classification, confidenceScore, explanation } = result;
    return JSON.stringify({
      status,
      language,
      classification,
      confidenceScore,
      explanation
    }, null, 2);
  };

