            <i className="fas fa-fingerprint text-2xl text-white"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter uppercase italic text-white">
              Vox<span className="text-indigo-500">Veritas</span>
            </h1>
            <p className="text-[10px] text-slate-500 font-bold tracking-[0.3em] uppercase">Forensic Voice Laboratory</p>
          </div>
        </div>
        <div className="text-[10px] text-indigo-400 font-black bg-indigo-500/10 px-4 py-2 rounded-full border border-indigo-500/20">
          SYSTEM_READY_2026
        </div>
      </header>

      <main className="w-full max-w-6xl grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Control Panel */}
        <div className="lg:col-span-4 space-y-6">
          <section className="bg-slate-900/40 p-6 rounded-3xl border border-white/5 backdrop-blur-md">
            <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4">01. Import Sample</h2>
            <div 
              className={`border-2 border-dashed rounded-2xl p-10 transition-all flex flex-col items-center justify-center gap-4 cursor-pointer
                ${state.audioFile ? 'border-indigo-500/50 bg-indigo-500/5' : 'border-slate-800 hover:border-indigo-500/40'}`}
              onClick={() => fileInputRef.current?.click()}
            >
              <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".mp3" />
              {!state.audioFile ? (
                <div className="text-center opacity-40">
                  <i className="fas fa-cloud-upload text-3xl mb-3"></i>
                  <p className="text-[10px] font-black uppercase">Click to Select MP3</p>
                </div>
              ) : (
                <div className="text-center">
