import { GoogleGenAI, Type } from "@google/genai";
import { Language, DetectionResult, Classification } from "./types";

export const analyzeVoiceAuthenticity = async (
  base64Audio: string,
  userSelectedLanguage: Language
): Promise<DetectionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    ROLE: VOXVERITAS NEURAL FORENSIC ENGINE (v3.8)
    LOCATION: GLOBAL CYBER-DEFENSE HUB (2026)

    PRIMARY OBJECTIVE: Classify audio as HUMAN or AI_GENERATED with zero-trust linguistic auditing.

    FORENSIC SCAN PROTOCOL:
    1. LINGUISTIC AUDIT: Identify language (Tamil, English, Hindi, Malayalam, Telugu).
    2. DISCREPANCY CHECK: Compare detected language against user input: "${userSelectedLanguage}".
    3. SPECTRAL ANALYSIS: Isolate frequencies >18kHz for synthetic quantization artifacts.
    4. PROSODIC STOCHASTICITY: Analyze variance in syllable onset. Human speech is chaotic; AI is metronomic.

    OUTPUT FORMAT: Strictly JSON.
    {
      "status": "success",
      "detectedLanguage": "Actual Language Name",
      "languageMismatch": boolean,
      "classification": "AI_GENERATED" | "HUMAN",
      "confidenceScore": float (0.00 to 1.00),
      "explanation": "Max 180 chars forensic rationale",
      "technicalArtifacts": ["Marker 1", "Marker 2", "Marker 3", "Marker 4"]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          { inlineData: { mimeType: "audio/mp3", data: base64Audio } },
          { text: `SCAN_INIT: Verify authenticity. Context: ${userSelectedLanguage}.` },
        ],
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1, // Near-deterministic for forensic consistency
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            detectedLanguage: { type: Type.STRING },
            languageMismatch: { type: Type.BOOLEAN },
            classification: { type: Type.STRING, enum: ["AI_GENERATED", "HUMAN"] },
            confidenceScore: { type: Type.NUMBER },
            explanation: { type: Type.STRING },
            technicalArtifacts: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["status", "detectedLanguage", "languageMismatch", "classification", "confidenceScore", "explanation", "technicalArtifacts"],
        },
      },
    });

    const resultText = response.text;
    if (!resultText) throw new Error("ERR_EMPTY_PAYLOAD");

    const json = JSON.parse(resultText);
    return {
      status: json.status,
      detectedLanguage: json.detectedLanguage,
      languageMismatch: json.languageMismatch,
      classification: json.classification as Classification,
      confidenceScore: json.confidenceScore,
      explanation: json.explanation,
      technicalArtifacts: json.technicalArtifacts,
    };
  } catch (err) {
    throw new Error("ERR_CORE_ENGINE_TIMEOUT");
  }
};

