    audioFile: null,
    audioBase64: null,
    selectedLanguage: Language.ENGLISH,
    isAnalyzing: false,
    result: null,
    error: null,
  });

  const [ticker, setTicker] = useState<string>("SYSTEM_READY_V3.8");
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Strict File Validation & Immediate JSON Fail-Fast
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const isMp3 = file.type === 'audio/mpeg' || file.type === 'audio/mp3' || file.name.toLowerCase().endsWith('.mp3');

    if (!isMp3) {
      const errorJson: DetectionResult = {
        status: 'error',
        detectedLanguage: 'NULL_STREAM',
        languageMismatch: false,
        classification: Classification.UNKNOWN,
        confidenceScore: 0,
        explanation: "FATAL: Protocol mismatch. VoxVeritas requires strictly compliant MP3 bitstreams for bit-depth validation. Input stream rejected by kernel.",
        errorCode: "ERR_BITSTREAM_VIOLATION"
      };

      setState(prev => ({ 
        ...prev, 
        audioFile: null, 
        audioBase64: null, 
        result: errorJson,
        error: "INVALID_BITSTREAM"
      }));
      setTicker("ERROR: KERNEL_HALT");
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      setState(prev => ({ 
        ...prev, 
        audioFile: file, 
        audioBase64: base64, 
        error: null, 
        result: null 
