           style={{ backgroundImage: `radial-gradient(#4f46e5 1px, transparent 1px)`, backgroundSize: '40px 40px' }}></div>

      {/* Lab HUD */}
      <header className="sticky top-0 z-50 bg-[#05070a]/80 backdrop-blur-xl border-b border-white/5">
        <div className="max-w-7xl mx-auto px-6 h-14 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-8 h-8 bg-indigo-600 rounded flex items-center justify-center shadow-[0_0_15px_rgba(79,70,229,0.4)]">
              <i className="fas fa-shield-halved text-white text-[10px]"></i>
            </div>
            <h1 className="text-[11px] font-black tracking-[0.3em] uppercase italic">
              Vox<span className="text-indigo-500">Veritas</span> <span className="text-slate-700 ml-2 not-italic font-mono">F-LAB_V3.8</span>
