export const analyzeVoiceAuthenticity = async (
  base64Audio: string,
  userSelectedLanguage: Language
): Promise<DetectionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    ROLE: VOXVERITAS LEAD FORENSIC ANALYST (2026)

    MISSION: Determine if audio is HUMAN or AI_GENERATED.

    CORE CONSTRAINTS:
    - Supported Languages: Tamil, English, Hindi, Malayalam, Telugu.
    - If audio is outside these 5, flag as "UNKNOWN_LINGUISTIC_PROFILE".
    - Explanation must be "Human-Centered": Speak like a forensic expert explaining to a non-technical jury. Use analogies.

    FORENSIC AUDIT STEPS:
    1. LINGUISTIC IDENTITY: Confirm language and check against User Context: "${userSelectedLanguage}".
    2. BREATH-TO-TONE RATIO: Check for biological air intake chaotic patterns.
    3. SPECTRAL FLOOR: Look for synthetic quantization (>18kHz).
    4. PROSODIC MAPPING: Measure variance in syllable duration.

    OUTPUT SCHEMA (STRICT JSON):
    {
      "status": "success",
      "detectedLanguage": "String",
      "languageMismatch": boolean,
      "classification": "AI_GENERATED" | "HUMAN",
      "confidenceScore": float,
      "explanation": "Human-friendly interpretation (e.g. 'This voice sounds too clean, lacking natural breathiness expected in human speech...')",
      "technicalArtifacts": [
        "Descriptive Name (e.g. Spectral Grain Deficiency)",
        "Descriptive Name (e.g. Metronomic Syllable Pulse)",
        "Descriptive Name",
        "Descriptive Name"
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          { inlineData: { mimeType: "audio/mp3", data: base64Audio } },
          { text: `START_AUDIT: User claims this is ${userSelectedLanguage}. Verify markers.` },
        ],
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        temperature: 0, 
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            detectedLanguage: { type: Type.STRING },
            languageMismatch: { type: Type.BOOLEAN },
            classification: { type: Type.STRING, enum: ["AI_GENERATED", "HUMAN"] },
            confidenceScore: { type: Type.NUMBER },
            explanation: { type: Type.STRING },
            technicalArtifacts: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["status", "detectedLanguage", "languageMismatch", "classification", "confidenceScore", "explanation", "technicalArtifacts"],
        },
      },
    });

    const resultText = response.text;
    if (!resultText) throw new Error("ERR_ANALYSIS_ABORTED");

    return JSON.parse(resultText);
  } catch (err) {
    throw new Error("CORE_ENGINE_TIMEOUT");
  }
};

import React, { useState, useRef } from 'react';
import { Language, AppState, Classification, DetectionResult } from './types';
import { analyzeVoiceAuthenticity } from './geminiService';

const LANGUAGES = [
  Language.TAMIL,
  Language.ENGLISH,
  Language.HINDI,
  Language.MALAYALAM,
  Language.TELUGU,
];

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    audioFile: null,
    audioBase64: null,
    selectedLanguage: Language.ENGLISH,
    isAnalyzing: false,
    result: null,
    error: null,
  });

  const [ticker, setTicker] = useState<string>("SYSTEM_IDLE");
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Reset previous state for new single file ingest
    setState(prev => ({ ...prev, result: null, error: null, audioFile: null, audioBase64: null }));

    const isMp3 = file.type === 'audio/mpeg' || file.type === 'audio/mp3' || file.name.toLowerCase().endsWith('.mp3');

    if (!isMp3) {
      const errorJson: DetectionResult = {
        status: 'error',
        detectedLanguage: 'NULL',
        languageMismatch: false,
        classification: Classification.UNKNOWN,
        confidenceScore: 0,
        explanation: "SYSTEM REJECTION: Incompatible bitstream. VoxVeritas only processes strictly compliant MP3 audio fragments to maintain forensic integrity.",
        errorCode: "ERR_PROTOCOL_VIOLATION"
      };
      setState(prev => ({ ...prev, result: errorJson, error: "BITSTREAM_ERR" }));
      setTicker("ERROR: INVALID_INPUT");
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      setState(prev => ({ ...prev, audioFile: file, audioBase64: base64 }));
      setTicker("SIGNAL_LOCKED: READY_FOR_SCAN");
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!state.audioBase64) return;
    setState(prev => ({ ...prev, isAnalyzing: true, error: null }));

    const steps = ["ISOLATING_PHONEMES", "SPECTRAL_MAPPING", "LINGUISTIC_AUDIT", "FINALIZING_REPORT"];
    let stepIdx = 0;
    const interval = setInterval(() => {
      if (stepIdx < steps.length) {
        setTicker(steps[stepIdx]);
        stepIdx++;
      }
    }, 400);

    try {
      const result = await analyzeVoiceAuthenticity(state.audioBase64, state.selectedLanguage);
      setState(prev => ({ ...prev, result, isAnalyzing: false }));
      setTicker("AUDIT_COMPLETE");
    } catch (err: any) {
      setState(prev => ({ ...prev, error: "FATAL_TIMEOUT", isAnalyzing: false }));
      setTicker("ENGINE_HALT");
    } finally {
      clearInterval(interval);
    }
  };

  return (
    <div className="min-h-screen bg-[#030508] text-slate-200 font-sans overflow-x-hidden selection:bg-indigo-500/30">
      <div className="fixed inset-0 pointer-events-none opacity-[0.02]" style={{ backgroundImage: `radial-gradient(#4f46e5 1px, transparent 1px)`, backgroundSize: '30px 30px' }}></div>

      {/* Lab Header */}
      <header className="sticky top-0 z-50 bg-[#06080c]/80 backdrop-blur-xl border-b border-white/5">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-600/30">
              <i className="fas fa-fingerprint text-white"></i>
            </div>
            <h1 className="text-[12px] font-black tracking-[0.4em] uppercase italic">
              Vox<span className="text-indigo-500">Veritas</span> <span className="text-slate-700 not-italic font-mono ml-2">v3.9_PRO</span>
            </h1>
          </div>
          <div className="hidden md:flex items-center gap-6">
            <div className="text-right">
              <p className="text-[8px] font-bold text-slate-500 uppercase tracking-widest">Neural Ticker</p>
              <p className="text-[10px] font-mono text-indigo-400 animate-pulse">{ticker}</p>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-6 md:p-10 grid grid-cols-1 lg:grid-cols-12 gap-10">

        {/* Left Control Column */}
        <div className="lg:col-span-4 space-y-8">
          <section className="bg-[#0a0d14] border border-white/5 rounded-[2rem] p-8 shadow-2xl relative overflow-hidden group">
            <div className="absolute -top-10 -right-10 w-32 h-32 bg-indigo-600/5 rounded-full blur-3xl group-hover:bg-indigo-600/10 transition-colors"></div>
            <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center gap-2">
              <i className="fas fa-cloud-arrow-up text-indigo-500"></i> Signal Ingest
            </h2>
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`border-2 border-dashed rounded-2xl p-10 flex flex-col items-center justify-center transition-all cursor-pointer
                ${state.audioFile ? 'border-indigo-500/50 bg-indigo-500/10' : 'border-slate-800 hover:border-indigo-500/30 hover:bg-white/[0.02]'}`}
            >
              <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".mp3" />
              <i className={`fas ${state.audioFile ? 'fa-circle-check text-indigo-400' : 'fa-microphone-lines text-slate-700'} text-4xl mb-4`}></i>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tight text-center truncate w-full">
