            <p className="text-[9px] text-slate-600 font-bold uppercase mb-4 leading-relaxed">
              VoxVeritas only supports: <span className="text-indigo-400">Tamil, English, Hindi, Malayalam, Telugu</span>. Any other languages will return a low-confidence score.
            </p>
            <div className="grid grid-cols-2 gap-2">
              {LANGUAGES.map(l => (
                <button
                  key={l}
                  onClick={() => setState(prev => ({ ...prev, selectedLanguage: l, result: null }))}
                  className={`py-3 rounded-xl text-[10px] font-black transition-all border uppercase tracking-widest
                    ${state.selectedLanguage === l ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg' : 'bg-white/5 border-white/5 text-slate-500 hover:text-slate-300'}`}
                >
                  {l}
                </button>
              ))}
            </div>
          </section>

          <button
            onClick={handleAnalyze}
            disabled={!state.audioBase64 || state.isAnalyzing}
            className={`w-full py-5 rounded-[1.5rem] font-black text-xs uppercase tracking-[0.4em] transition-all
              ${state.isAnalyzing ? 'bg-slate-900 text-slate-700 cursor-not-allowed' : 'bg-white text-black hover:bg-indigo-600 hover:text-white shadow-2xl shadow-indigo-500/20 active:scale-95'}`}
          >
