          required: ["status", "detectedLanguage", "classification", "confidenceScore", "explanation", "technicalArtifacts"],
        },
      },
    });

    const resultText = response.text;
    if (!resultText) throw new Error("ERR_VOX_SILENCE");

    const json = JSON.parse(resultText);
    return {
      ...json,
      languageMismatch: false // No longer applicable as we don't compare against user input
    };
  } catch (err) {
    throw new Error("CORE_UPLINK_TIMEOUT");
  }
};

