  selectedLanguage: any; // Deprecated but kept to avoid structural breakage
  isAnalyzing: boolean;
  result: DetectionResult | null;
  error: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { DetectionResult, Classification } from "./types";

export const analyzeVoiceAuthenticity = async (
  base64Audio: string
): Promise<DetectionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    ROLE: VOXVERITAS LEAD FORENSIC SPECIALIST

    MISSION: Determine if an audio signal is BIOLOGICAL (Human) or SYNTHETIC (AI).

    SPECIALIZED LANGUAGES: Tamil, English, Hindi, Malayalam, Telugu.

    OPERATIONAL PROTOCOL:
    1. Identify the language.
    2. If the language is NOT one of the 5 listed above, perform a "Universal Forensic Audit." This focuses on cross-linguistic markers like spectral quantization and prosodic regularity.
    3. EXPLANATION STYLE: Be conversational but expert. Explain the "vibe" of the voice's physics. (e.g., "The speaker has natural fluctuations in their breath that AI struggles to mimic" or "The syllables are too perfectly spaced, suggesting a digital clock-source").
    4. DO NOT wrap your response in quotes or use overly dramatic detective language.

    OUTPUT SCHEMA (STRICT JSON):
    {
      "status": "success",
      "detectedLanguage": "Name of Language",
      "classification": "AI_GENERATED" | "HUMAN",
      "confidenceScore": float (0.00-1.00),
      "explanation": "A natural, humanized diagnostic summary of the findings.",
      "technicalArtifacts": ["Marker 1", "Marker 2", "Marker 3", "Marker 4"]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          { inlineData: { mimeType: "audio/mp3", data: base64Audio } },
          { text: "SIGNAL_INPUT: Execute autonomous biometric verification." },
        ],
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        temperature: 0, 
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            detectedLanguage: { type: Type.STRING },
            classification: { type: Type.STRING, enum: ["AI_GENERATED", "HUMAN"] },
            confidenceScore: { type: Type.NUMBER },
            explanation: { type: Type.STRING },
            technicalArtifacts: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["status", "detectedLanguage", "classification", "confidenceScore", "explanation", "technicalArtifacts"],
        },
      },
    });

    const resultText = response.text;
    if (!resultText) throw new Error("CORE_ENGINE_SILENCE");

    const json = JSON.parse(resultText);
    return {
      ...json,
      languageMismatch: false
    };
  } catch (err) {
    throw new Error("CORE_UL_ERROR");
  }
};

