import React, { useState, useRef, useEffect } from 'react';
import { AppState, Classification, DetectionResult } from './types';
import { analyzeVoiceAuthenticity } from './geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    audioFile: null,
    audioBase64: null,
    selectedLanguage: null,
    isAnalyzing: false,
    result: null,
    error: null,
  });

  const [statusText, setStatusText] = useState<string>("SYSTEM READY");
  const [sessionId, setSessionId] = useState<string>("VX-0000");
  const [showLog, setShowLog] = useState<boolean>(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const generateId = () => {
    return `VX-${Math.floor(1000 + Math.random() * 9000)}-${Math.random().toString(36).substring(2, 5).toUpperCase()}`;
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Generate static ID for this specific session/file
    const newId = generateId();
    setSessionId(newId);

    setState({
      audioFile: null,
      audioBase64: null,
      selectedLanguage: null,
      isAnalyzing: false,
      result: null,
      error: null,
    });

    const isMp3 = file.type === 'audio/mpeg' || file.type === 'audio/mp3' || file.name.toLowerCase().endsWith('.mp3');

    if (!isMp3) {
      const errorJson: DetectionResult = {
        status: 'error',
        detectedLanguage: 'NULL',
        languageMismatch: false,
        classification: Classification.UNKNOWN,
        confidenceScore: 0,
        explanation: "The intelligence core requires high-fidelity MP3 encoding to extract phonetic artifacts.",
        errorCode: "MIME_PROTOCOL_VIOLATION"
      };
      setState(prev => ({ ...prev, result: errorJson, error: "BITSTREAM_ERR" }));
      setStatusText("PROTOCOL ERROR");
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      setState(prev => ({ ...prev, audioFile: file, audioBase64: base64 }));
      setStatusText("SIGNAL LOCKED");
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!state.audioBase64) return;
    setState(prev => ({ ...prev, isAnalyzing: true, error: null, result: null }));

    const steps = ["ISOLATING SIGNAL", "MAPPING FREQUENCIES", "NEURAL VERIFICATION"];
    let stepIdx = 0;
    const interval = setInterval(() => {
      if (stepIdx < steps.length) {
        setStatusText(steps[stepIdx]);
        stepIdx++;
      }
    }, 800);

    try {
      const result = await analyzeVoiceAuthenticity(state.audioBase64);
      setState(prev => ({ ...prev, result, isAnalyzing: false }));
      setStatusText("ANALYSIS COMPLETE");
    } catch (err: any) {
      setState(prev => ({ ...prev, error: "TIMEOUT", isAnalyzing: false }));
      setStatusText("SYSTEM HALT");
    } finally {
      clearInterval(interval);
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center px-6 py-12 md:py-24 max-w-6xl mx-auto">

      {/* Premium Header */}
      <header className="w-full flex justify-between items-end mb-16 md:mb-32">
        <div className="flex flex-col gap-1">
          <h1 className="text-xl md:text-2xl font-extrabold tracking-tighter uppercase italic leading-none">
            Vox<span className="opacity-40">Veritas</span>
          </h1>
          <p className="text-[10px] font-medium tracking-[0.3em] opacity-30 uppercase">Intelligence Lab v4.1</p>
        </div>
        <div className="text-right hidden sm:block">
          <p className="text-[10px] font-bold opacity-30 uppercase tracking-widest mb-1">Session Protocol</p>
          <p className="text-sm font-light opacity-80 tracking-tight">{sessionId}</p>
        </div>
      </header>

      {/* The Stage */}
      <div className="w-full flex flex-col items-center">
        {!state.result && !state.isAnalyzing ? (
          <div className="w-full max-w-2xl animate-in fade-in slide-in-from-bottom-8 duration-1000">
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="premium-glass halo-shadow rounded-[3rem] p-16 md:p-24 flex flex-col items-center justify-center cursor-pointer group transition-all"
            >
              <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".mp3" />
              <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center mb-10 group-hover:bg-white/10 transition-all duration-500">
                <i className={`fas ${state.audioFile ? 'fa-check text-emerald-400' : 'fa-plus text-white/40'} text-xl`}></i>
              </div>
              <h2 className="text-2xl font-light text-center mb-3">
                {state.audioFile ? state.audioFile.name : 'Ingest Voice Profile'}
              </h2>
              <p className="text-sm opacity-30 font-medium tracking-wide uppercase">Select high-fidelity MP3</p>
            </div>

            <div className="mt-12 flex justify-center">
              <button
                onClick={handleAnalyze}
                disabled={!state.audioBase64}
                className={`px-12 py-5 rounded-full text-xs font-bold uppercase tracking-[0.2em] shadow-xl
                  ${!state.audioBase64 ? 'bg-white/5 text-white/20 cursor-not-allowed' : 'btn-premium'}`}
              >
                Analyze Authenticity
              </button>
            </div>
          </div>
        ) : state.isAnalyzing ? (
          <div className="flex flex-col items-center py-20 animate-in fade-in duration-700">
            <div className="w-32 h-32 bg-white/5 liquid-morph mb-12 flex items-center justify-center overflow-hidden border border-white/10 shadow-[0_0_50px_rgba(255,255,255,0.05)]">
               <div className="w-full h-1 bg-white/20 animate-[loading_2s_infinite]"></div>
            </div>
            <p className="text-sm font-medium tracking-[0.4em] opacity-40 uppercase">{statusText}</p>
          </div>
        ) : (
          <div className="w-full max-w-4xl space-y-12 animate-in fade-in zoom-in-95 duration-1000">
            {/* Main Result Card */}
            <div className="premium-glass halo-shadow rounded-[4rem] p-10 md:p-16 flex flex-col md:flex-row items-center gap-16 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-8 opacity-5">
                <i className="fas fa-certificate text-6xl"></i>
              </div>

              {/* Radial Gauge */}
              <div className="relative w-56 h-56 flex-shrink-0">
                <svg viewBox="0 0 100 100" className="w-full h-full transform -rotate-90">
                  <circle cx="50" cy="50" r="48" stroke="rgba(255,255,255,0.03)" strokeWidth="1.5" fill="none" />
                  <circle cx="50" cy="50" r="48" 
                    stroke={state.result?.classification === Classification.AI_GENERATED ? '#ffffff' : '#ffffff'} 
                    strokeWidth="2.5" fill="none" strokeDasharray="301.59" strokeDashoffset={301.59 - (301.59 * (state.result?.confidenceScore || 0))} 
                    strokeLinecap="round" className="transition-all duration-[2s] ease-out opacity-80" />
                </svg>
                <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className="text-6xl font-extrabold tracking-tighter text-white">
                    {Math.round((state.result?.confidenceScore || 0) * 100)}%
                  </span>
                  <span className="text-[9px] font-bold uppercase tracking-[0.3em] opacity-30 mt-1">Certainty</span>
                </div>
              </div>

              <div className="flex-1 text-center md:text-left">
                <div className="inline-flex items-center gap-2 px-3 py-1 bg-white/5 rounded-full border border-white/10 mb-6">
                  <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></span>
                  <span className="text-[9px] font-bold uppercase tracking-widest opacity-60">Verified {state.result?.detectedLanguage}</span>
                </div>
                <h3 className={`text-6xl md:text-8xl font-black italic tracking-tighter uppercase leading-none mb-4
