                <p className="text-xl font-light opacity-60 leading-relaxed max-w-lg">
                  {state.result?.explanation}
                </p>
              </div>
            </div>

            {/* Marker Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <div className="premium-glass rounded-[2.5rem] p-10 space-y-6">
                  <h4 className="text-[10px] font-bold uppercase tracking-[0.4em] opacity-30">Biometric Signatures</h4>
                  <div className="space-y-4">
                    {state.result?.technicalArtifacts?.map((m, i) => (
                      <div key={i} className="flex items-center justify-between group">
                        <span className="text-xs font-medium opacity-60 group-hover:opacity-100 transition-opacity">{m}</span>
                        <div className="h-px flex-1 mx-4 bg-white/5"></div>
                        <i className="fas fa-check text-[8px] opacity-20"></i>
                      </div>
                    ))}
                  </div>
