import { GoogleGenAI, Type } from "@google/genai";
import { DetectionResult, Classification } from "./types";

export const analyzeVoiceAuthenticity = async (
  base64Audio: string
): Promise<DetectionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Using gemini-3-flash-preview for high-speed forensic analysis
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    ROLE: VOXVERITAS SENIOR LINGUISTIC FORENSIC ANALYST

    CORE MISSION: Perform a deep-layer audit on the provided audio signal to distinguish between BIOLOGICAL (Human) and SYNTHETIC (AI/Neural) origins.

    PRIMARY SUITE: Optimized for Tamil, English, Hindi, Malayalam, and Telugu.

    ANALYSIS CRITERIA:
    1. PROSODIC JITTER: Human speech has micro-fluctuations in pitch and timing. AI is often too "perfect" or metronomic.
    2. SPECTRAL QUANTIZATION: Look for digital "stepping" in the 16kHz+ range, characteristic of neural vocoders.
    3. ARTIFACT DETECTION: Identify "clipping" in phoneme transitions, especially in Dravidian retroflex sounds (Tamil/Malayalam) or Indo-Aryan aspirations (Hindi).
    4. LANGUAGE DETECTION: Identify which of the 5 languages is present. If none, classify as "Universal Profile."

    OUTPUT STYLE:
    - Explanation: Professional, slightly clinical but accessible.
    - Status: Must be "success".
    - Confidence: High (0.85+) for clear AI signatures.

    STRICT JSON SCHEMA:
    {
      "status": "success",
      "detectedLanguage": "Name of Language",
      "classification": "AI_GENERATED" | "HUMAN",
      "confidenceScore": float,
      "explanation": "Detailed forensic reasoning.",
      "technicalArtifacts": ["Specific Observation 1", "Specific Observation 2", "Specific Observation 3"]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          { inlineData: { mimeType: "audio/mp3", data: base64Audio } },
          { text: "SIGNAL_INPUT: Execute biometric verification across spectral and prosodic dimensions." },
        ],
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1, // Low temperature for consistent forensic results
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            detectedLanguage: { type: Type.STRING },
            classification: { type: Type.STRING, enum: ["AI_GENERATED", "HUMAN"] },
            confidenceScore: { type: Type.NUMBER },
            explanation: { type: Type.STRING },
            technicalArtifacts: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["status", "detectedLanguage", "classification", "confidenceScore", "explanation", "technicalArtifacts"],
        },
      },
    });

    const resultText = response.text;
    if (!resultText) throw new Error("ENGINE_SILENCE");

    const json = JSON.parse(resultText);
    return {
      ...json,
      languageMismatch: false
    };
  } catch (err) {
    console.error("Forensic Error:", err);
    throw new Error("CORE_ENGINE_TIMEOUT");
  }
};

