    const file = e.target.files?.[0];
    if (!file) return;

    const newId = generateSessionId();
    setSessionId(newId);

    setState({
      audioFile: null,
      audioBase64: null,
      selectedLanguage: null,
      isAnalyzing: false,
      result: null,
      error: null,
