import { GoogleGenAI, Type } from "@google/genai";
import { DetectionResult, Classification } from "./types";

export const analyzeVoiceAuthenticity = async (
  base64Audio: string
): Promise<DetectionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Using gemini-3-flash-preview for high-speed forensic analysis
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    ROLE: VOXVERITAS SENIOR LINGUISTIC FORENSIC ANALYST

    CORE MISSION: Distinguish between HUMAN (Biological) and AI_GENERATED (Synthetic) origins.

    PRIMARY SUITE: Optimized for Tamil, English, Hindi, Malayalam, and Telugu.

    INTERPRETATION GUIDELINE: 
    - Your "explanation" must be EXTREMELY HUMAN-FRIENDLY. 
    - Use "The Analogy Principle": Explain technical anomalies using common human experiences.
    - If you find high-frequency quantization, say: "The high notes in the speech have a digital 'crunchiness' or 'fuzz' that sounds like a low-quality recording, which is a common footprint of AI_GENERATED voices."
    - If you find a lack of micro-jitter, say: "The voice is a bit too 'perfect.' Real HUMAN voices have tiny, shaky fluctuations that AI_GENERATED models often smooth out to make it sound better than a real person."
    - If you find artificial breaths, say: "The breathing sounds like it was 'pasted' in. It's too regular, like a metronome, whereas a HUMAN breathes differently depending on the length of the sentence."

    ANALYSIS CRITERIA:
    1. PROSODIC JITTER: HUMAN speech has micro-fluctuations. AI_GENERATED is often too "perfect."
    2. SPECTRAL QUANTIZATION: Digital "stepping" in high frequencies.
    3. ARTIFACT DETECTION: Identify "clipping" in phoneme transitions, especially in Dravidian retroflex sounds or Indo-Aryan aspirations.
    4. LANGUAGE DETECTION: Identify which of the 5 languages is present.

    STRICT JSON SCHEMA:
    {
      "status": "success",
      "detectedLanguage": "Name of Language",
      "classification": "AI_GENERATED" | "HUMAN",
      "confidenceScore": float,
      "explanation": "Humanized, analogy-driven interpretation of the findings.",
      "technicalArtifacts": ["Specific Technical Marker 1", "Marker 2", "Marker 3"]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          { inlineData: { mimeType: "audio/mp3", data: base64Audio } },
          { text: "SIGNAL_INPUT: Perform verification. Classify as either AI_GENERATED or HUMAN. Ensure the explanation is clear to non-technical users using analogies." },
        ],
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1,
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            detectedLanguage: { type: Type.STRING },
            classification: { type: Type.STRING, enum: ["AI_GENERATED", "HUMAN"] },
            confidenceScore: { type: Type.NUMBER },
            explanation: { type: Type.STRING },
            technicalArtifacts: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["status", "detectedLanguage", "classification", "confidenceScore", "explanation", "technicalArtifacts"],
        },
      },
    });

    const resultText = response.text;
    if (!resultText) throw new Error("ENGINE_SILENCE");

    const json = JSON.parse(resultText);
    return {
      ...json,
      languageMismatch: false
    };
  } catch (err) {
    console.error("Forensic Error:", err);
    throw new Error("CORE_ENGINE_TIMEOUT");
  }
};

