            <p className="text-[9px] font-bold tracking-[0.4em] opacity-30 uppercase">Neural Forensic Lab</p>
          </div>
        </div>
        <div className="flex items-center gap-4 md:gap-8">
          <div className="text-right hidden sm:block">
